@page "/notepad"
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="notepad-container">
    <textarea class="form-control" @bind="content" @bind:event="oninput" @bind:after="OnContentChanged" placeholder="Type your notes here..." />

    <div class="notepad-toolbar">
        <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
        <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
        <span class="notepad-status">@statusMessage</span>
    </div>
</div>

@code {
    private string content = string.Empty;
    private string statusMessage = string.Empty;
    private string lastSavedContent = string.Empty;
    private IJSObjectReference? module;
    private DotNetObjectReference<Notepad>? dotNetRef;
    private System.Timers.Timer? autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        module = await JS.InvokeAsync<IJSObjectReference>(
            "import", $"./{ComponentUtilities.GetComponentJavaScriptPath(nameof(Notepad), "Components/Pages")}");

        dotNetRef = DotNetObjectReference.Create(this);
        await module.InvokeVoidAsync("initialize", dotNetRef);

        var saved = await module.InvokeAsync<string?>("load");
        if (!string.IsNullOrEmpty(saved))
        {
            content = saved;
            lastSavedContent = saved;
            statusMessage = "Restored from saved data";
            StateHasChanged();
        }

        autoSaveTimer = new System.Timers.Timer(30_000);
        autoSaveTimer.Elapsed += async (_, _) => await InvokeAsync(AutoSave);
        autoSaveTimer.Start();
    }

    private async Task OnContentChanged()
    {
        bool dirty = content != lastSavedContent;
        if (module is not null)
        {
            await module.InvokeVoidAsync("setDirty", dirty);
        }
    }

    private async Task AutoSave()
    {
        if (content == lastSavedContent) return;
        await SaveContent();
    }

    private async Task SaveNow()
    {
        await SaveContent();
    }

    private async Task SaveContent()
    {
        if (module is null) return;

        await module.InvokeVoidAsync("save", content);
        lastSavedContent = content;
        await module.InvokeVoidAsync("setDirty", false);
        statusMessage = $"Last saved at {DateTime.Now:HH:mm:ss}";
        StateHasChanged();
    }

    private async Task Clear()
    {
        content = string.Empty;
        lastSavedContent = string.Empty;

        if (module is not null)
        {
            await module.InvokeVoidAsync("clear");
            await module.InvokeVoidAsync("setDirty", false);
        }

        statusMessage = "Cleared";
    }

    public async ValueTask DisposeAsync()
    {
        autoSaveTimer?.Stop();
        autoSaveTimer?.Dispose();

        if (module is not null)
        {
            await module.InvokeVoidAsync("dispose");
            await module.DisposeAsync();
        }

        dotNetRef?.Dispose();
    }
}

